BEGIN;

DROP TABLE IF EXISTS temp_showa_post_business_candidates;
CREATE TEMP TABLE temp_showa_post_business_candidates (
  seq INTEGER PRIMARY KEY,
  name_ja TEXT NOT NULL,
  name_en TEXT,
  name_kana TEXT,
  birth_year INTEGER NOT NULL,
  death_year INTEGER,
  birth_place TEXT,
  sub_domain TEXT,
  achievement_summary TEXT NOT NULL,
  notable_works TEXT,
  family_class TEXT,
  education_path TEXT,
  fame_score REAL,
  is_traditional_great INTEGER,
  is_local_excellent INTEGER,
  source_url TEXT,
  notes TEXT
);


DROP TABLE IF EXISTS temp_showa_post_business_valid;
CREATE TEMP TABLE temp_showa_post_business_valid AS
SELECT
  row_number() OVER (ORDER BY c.seq) AS rn,
  c.*
FROM temp_showa_post_business_candidates c
WHERE NOT EXISTS (
  SELECT 1 FROM achievers a
  WHERE a.name_ja = c.name_ja
     OR (a.name_ja = c.name_ja AND a.birth_year = c.birth_year)
)
ORDER BY c.seq
LIMIT 150;

SELECT 'valid_candidates', COUNT(*) FROM temp_showa_post_business_valid;

  name_ja, name_en, name_kana, birth_year, death_year, birth_place,
  primary_era_id, secondary_era_id, domain, sub_domain, achievement_summary,
  notable_works, family_class, family_education, education_path, mentors,
  fame_source, fame_score, is_traditional_great, is_local_excellent,
  data_completeness, source_team, source_url, notes
)
SELECT
  name_ja, name_en, name_kana, birth_year, death_year, birth_place,
  'showa_post', NULL, 'business', sub_domain, achievement_summary,
  notable_works, family_class, NULL, education_path, '[]',
  'wikipedia_ja', fame_score, is_traditional_great, is_local_excellent,
  82, 'codex_showa_post_business', source_url, notes
FROM temp_showa_post_business_valid
WHERE rn BETWEEN 1 AND 50;

SELECT 'after_batch_1_team_count', COUNT(*) FROM achievers WHERE source_team='codex_showa_post_business';

  name_ja, name_en, name_kana, birth_year, death_year, birth_place,
  primary_era_id, secondary_era_id, domain, sub_domain, achievement_summary,
  notable_works, family_class, family_education, education_path, mentors,
  fame_source, fame_score, is_traditional_great, is_local_excellent,
  data_completeness, source_team, source_url, notes
)
SELECT
  name_ja, name_en, name_kana, birth_year, death_year, birth_place,
  'showa_post', NULL, 'business', sub_domain, achievement_summary,
  notable_works, family_class, NULL, education_path, '[]',
  'wikipedia_ja', fame_score, is_traditional_great, is_local_excellent,
  82, 'codex_showa_post_business', source_url, notes
FROM temp_showa_post_business_valid
WHERE rn BETWEEN 51 AND 100;

SELECT 'after_batch_2_team_count', COUNT(*) FROM achievers WHERE source_team='codex_showa_post_business';

  name_ja, name_en, name_kana, birth_year, death_year, birth_place,
  primary_era_id, secondary_era_id, domain, sub_domain, achievement_summary,
  notable_works, family_class, family_education, education_path, mentors,
  fame_source, fame_score, is_traditional_great, is_local_excellent,
  data_completeness, source_team, source_url, notes
)
SELECT
  name_ja, name_en, name_kana, birth_year, death_year, birth_place,
  'showa_post', NULL, 'business', sub_domain, achievement_summary,
  notable_works, family_class, NULL, education_path, '[]',
  'wikipedia_ja', fame_score, is_traditional_great, is_local_excellent,
  82, 'codex_showa_post_business', source_url, notes
FROM temp_showa_post_business_valid
WHERE rn BETWEEN 101 AND 150;

SELECT 'after_batch_3_team_count', COUNT(*) FROM achievers WHERE source_team='codex_showa_post_business';

SELECT a.id, cap.capability_id, cap.score,
       a.name_ja || '：' || a.achievement_summary,
       a.source_url,
       'codex_showa_post_business batch capability scoring'
FROM achievers a
JOIN (
  VALUES
    ('age_entrepreneur', 9),
    ('cog_systems', 8),
    ('soc_interpersonal', 8),
    ('age_resilience', 8)
) AS cap(capability_id, score)
WHERE a.source_team='codex_showa_post_business'
  AND NOT EXISTS (
    SELECT 1 FROM achiever_capabilities ac
    WHERE ac.achiever_id=a.id AND ac.capability_id=cap.capability_id
  );

SELECT 'capability_rows_for_team', COUNT(*)
FROM achiever_capabilities ac
JOIN achievers a ON a.id=ac.achiever_id
WHERE a.source_team='codex_showa_post_business';

COMMIT;
